Here is my answer to Q.3
i used \ at the start of `#include` because leetcode is treating it like something different than normal text

The idea is: 
whenever a query of type-2 comes then I find minimum element and its index and update that place capacity to infinity denoting there is no crop at that place anymore.
Now type-2 query will be of complexity `n * logn` only when there are `n` queries of type-1 before it.

So, the total complexity will be `O(n logn)`

```

\#include <bits/stdc++.h>

using i64 = long long;

constexpr int inf = 1e9 + 10;

struct segtree
{
    const int n;
    std::vector<int> tree;

    segtree(int n) : n(n), tree(4 * n, inf) {}

    void update(int i, int x, int p, int ns, int ne)
    {
        if (ns == ne)
            tree[p] = x;
        else
        {
            int nm = (ns + ne) / 2;

            if (i <= nm)
                update(i, x, p * 2 + 1, ns, nm);
            else
                update(i, x, p * 2 + 2, nm + 1, ne);

            tree[p] = std::min(tree[(p << 1) + 1], tree[(p << 1) + 2]);
        }
    } 

    void update(int p, int x)
    {
        update(p, x, 0, 0, n - 1);
    }

    std::pair<int, int> query(int l, int r, int p, int ns, int ne)
    {
        if (ns > r or ne < l)
            return {inf, -1};

        if (ns == ne)
            return {tree[p], ns};

        int nm = (ns + ne) / 2;
        auto [minl, idl] = query(l, r, (p << 1) + 1, ns, nm);
        auto [minr, idr] = query(l, r, (p << 1) + 2, nm + 1, ne);

        if (minl < minr)
            return {minl, idl};
        else
            return {minr, idr};
    }

    auto query(int l, int r)
    {
        return query(l, r, 0, 0, n - 1);
    }
};

int main()
{
    int n;
    std::cin >> n;

    segtree st(n);
    int q;
    std::cin >> q;

    while (q--)
    {
        int t;
        std::cin >> t;

        if (t == 1)
        {
            int i, c;
            std::cin >> i >> c;

            st.update(i, c);
        }
        else
        {
            int l, r, w;
            std::cin >> l >> r >> w;
            r--;

            int count = 0;

            while (true)
            {
                auto [min, min_id] = st.query(l, r);
                if (min > w)
                    break;

                st.update(min_id, inf);
                count++;
            }

            std::cout << count << "\n";
        }
    }
}
```

Question 2

Count the subarrays in which there is no subarray with sum 0.

use inclusion-exclusion principle
indexing 1-based
assign answer as n * ( n + 1) / 2;
now remove the bad parts it means which contain sum as 0.

use prefix sum on arrays 

initialise start_point as 0 and mp[0] = 0;

pfx[i] = pfx[i - 1] + arr[i];
if we found pfx[i] in mp then we found subarray with sum 0 then remove all the subarrays which contains this part.

if (mp[pfx[i]] >= start) then
       minus += (mp[pfx[i]] - start + 1) * (n - i + 1);
set mp[pfx[i]] = i;

now initialise start as mp[pfx[i]] + 1 because we do not consider the duplicate subarrays again 

------------------------------------------------------------------------------------------------------------------------------------------------

#include<bits/stdc++.h>
using namespace std;
[#include](https://leetcode.com/problems/minimum-interval-to-include-each-query) <ext/pb_ds/assoc_container.hpp>
[#include](https://leetcode.com/problems/minimum-interval-to-include-each-query) <ext/pb_ds/tree_policy.hpp>
using namespace __gnu_pbds;
#define  FIO     ios_base::sync_with_stdio(false);cin.tie(NULL);
#define  int     long long
#define  f       first
#define  s       second
#define  pb      push_back
#define  pii     pair<int,int>
#define  all(x)  x.begin(), x.end()
#define  endl    '\n'
const int Max = 2e5 + 10;
int n;
int arr[Max], pfx[Max];


void solve() {
    cin >> n;
    for (int i = 1; i <= n; ++i) cin >> arr[i];

    int start = 0, total = (n * (n + 1)) / 2, minus = 0;
    unordered_map<int, int> mp;
    mp[0] = 0;
    for (int i = 1; i <= n; ++i) {
        pfx[i] = pfx[i - 1] + arr[i];
        if (mp.find(pfx[i]) != mp.end() && mp[pfx[i]] >= start) {
            minus += (mp[pfx[i]] - start + 1) * (n - i + 1);
            start = mp[pfx[i]] + 1;
        }
        mp[pfx[i]] = i;
    }

    cout << total - minus << endl;
}

int32_t main()
{
    FIO

    int t = 1;
    while (t--){
        solve();
    }
    return 0;
}

`My approach for Problem 2.`

`TC - O(N*log(N)), can be reduced to O(N) using unordered_map`
`SC - O(N)`
```
long long int totalBeautifulSubarrays(vector<int>&A){
    int N = A.size();
    map<int, int> occurrence;
    occurrence[0] = -1;
    long long int prefSum = 0;
    long long int ans = 1ll*N*(N+1)/2;
    int lastProcess = -1;
    for(int i=0; i<N; i++){
        prefSum += A[i];
        if(occurrence.count(prefSum)){
            // need of `lastProcess` to remove duplicate counts.
            int j = occurrence[prefSum]+1;
            // sum of subarray A[j...i] = 0;
            if(j>lastProcess){
                ans -= 1ll*(j-lastProcess)*(N-i);
                lastProcess = j;
            }
        }
        occurrence[prefSum] = i;
    }
    return ans;
}
